insert into content_tips (id, course_id, unit_order, cefr_level, skill, type, topic, title, body, example) values
('11d908d9-3e7d-52ed-b083-af18d03b11a3'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,13,'B1',$p$writing$p$,$p$gramatica$p$,$p$subjonctif_present$p$,$p$El subjonctif: cuando el deseo manda sobre el verbo$p$,$p$Tras las expresiones de necesidad, deseo, duda o emoción (il faut que, je veux que, bien que, pour que) el verbo va en subjonctif présent, no en indicativo. Se forma con la raíz de la 3.ª persona del plural del presente + -e, -es, -e, -ions, -iez, -ent, pero cuidado con los irregulares clave: être → soit, avoir → ait, aller → aille, faire → fasse, pouvoir → puisse. El error típico del hispanohablante es olvidar el que obligatorio: no se dice «il faut je parte» sino «il faut que je parte». Si el sujeto es el mismo, usa el infinitivo: «je veux partir», no «je veux que je parte».$p$,$p$Il faut que tu sois à l'heure. · Bien qu'il fasse froid, on sort. · Je veux qu'elle aille chez le médecin.$p$),
('f8b38d14-0452-528a-afa4-980ae9614fcd'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,14,'B1',$p$writing$p$,$p$gramatica$p$,$p$futur_conditionnel_hypothese$p$,$p$Si + imparfait → conditionnel: soñar con lo posible$p$,$p$Para hablar de una hipótesis poco probable o imaginaria en el presente, el francés usa la estructura «si + imparfait, conditionnel présent», igual que el español «si + imperfecto de subjuntivo, condicional». El conditionnel se forma sobre el infinitivo (como el futur) + las terminaciones del imparfait: -ais, -ais, -ait, -ions, -iez, -aient. El error más frecuente es meter el conditionnel dentro del «si»: NUNCA se dice «si j'aurais», sino «si j'avais». El condicional va solo en la otra parte de la frase. Recuerda también no confundir futur (je parlerai, -ai) y conditionnel (je parlerais, -ais), que suenan casi igual.$p$,$p$Si j'avais le temps, je voyagerais plus. · Si tu étais riche, qu'est-ce que tu ferais ? · Nous irions à la plage s'il faisait beau.$p$),
('18bfdffb-8484-549f-a3a6-d951833b5d39'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,15,'B1',$p$reading$p$,$p$gramatica$p$,$p$pronoms_relatifs$p$,$p$Qui, que, dont, où: encadenar ideas con precisión$p$,$p$Los pronombres relativos evitan repetir el nombre y unen dos frases. Qui es el sujeto (le train QUI arrive = el tren que llega); que es el complemento directo (le livre QUE je lis = el libro que leo). Dont reemplaza un complemento con «de»: parler de → «l'homme dont je parle»; avoir besoin de → «la chose dont j'ai besoin». Où sirve para lugar y tiempo: «la ville où j'habite», «le jour où il est parti». El gran fallo del hispanohablante es usar siempre «que»: en español «el hombre DE QUE hablo» se dice con dont, y «el día EN QUE llegó» se dice con où, nunca con que.$p$,$p$C'est l'ami dont je t'ai parlé. · Le café où nous nous sommes rencontrés a fermé. · La femme qui chante est ma sœur.$p$),
('7a0e8651-e305-5d42-9658-b5035513b6cd'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,16,'B1',$p$writing$p$,$p$gramatica$p$,$p$accord_participe_passe$p$,$p$El participio que concuerda... o no$p$,$p$Con être (verbos de movimiento y pronominales), el participio concuerda siempre con el sujeto en género y número: «Elle est partie», «Ils sont venus». Con avoir NO concuerda con el sujeto, pero SÍ con el complemento directo si va ANTES del verbo: «les fleurs que j'ai achetées» (achetées concuerda con «les fleurs», que va delante). Si el COD va detrás, no hay concordancia: «j'ai acheté des fleurs». El hispanohablante suele olvidar la concordancia con être («elle est parti» es un error) o intentar concordar siempre con avoir. La clave: con avoir, mira si hay un COD delante.$p$,$p$Marie est arrivée hier. · Les lettres que tu as écrites sont là. · Nous avons mangé la tarte (sin concordancia, COD detrás).$p$),
('67079217-4b23-5bc8-bef8-15f2663a7ac4'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,17,'B1',$p$listening$p$,$p$gramatica$p$,$p$discours_indirect$p$,$p$Del estilo directo al indirecto: los tiempos retroceden$p$,$p$Al pasar de lo que alguien dijo al discurso indirecto en pasado, los tiempos «retroceden»: presente → imparfait, futur → conditionnel, passé composé → plus-que-parfait. «Il a dit : je suis fatigué» se vuelve «Il a dit qu'il était fatigué». También cambian los pronombres y a menudo se introduce con que. Para preguntas sin palabra interrogativa se usa si: «Est-ce que tu viens ?» → «Il a demandé si je venais». El error típico es mantener el presente: no se dice «il a dit qu'il est fatigué» cuando el marco es pasado, sino «qu'il était fatigué». Ojo: si el marco es presente, no hay retroceso.$p$,$p$Elle a dit qu'elle avait faim. · Il a demandé si nous étions prêts. · Je pensais que tu viendrais plus tôt.$p$),
('8232717d-789e-563e-b5a6-3319ad9dc1b9'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,18,'B1',$p$speaking$p$,$p$gramatica$p$,$p$pronoms_complements$p$,$p$Le, lui, y, en: el orden secreto de los pronombres$p$,$p$Le/la/les reemplazan el complemento directo (je LE vois); lui/leur el indirecto (je LUI parle = a él/ella). Y sustituye «à + cosa o lugar» (j'y pense = pienso en ello; j'y vais = voy allí) y en sustituye «de + cosa» o una cantidad (j'EN veux = quiero de eso; j'en ai trois = tengo tres). Cuando hay dos pronombres juntos, el orden es fijo: me/te/nous/vous, luego le/la/les, luego lui/leur, luego y, luego en. Así «je te le donne», «je le lui donne», «il y en a». El hispanohablante tiende a poner el pronombre detrás del verbo como en español; en francés va SIEMPRE delante (salvo en imperativo afirmativo: «donne-le-moi»).$p$,$p$Je le lui ai donné. · Il y en a beaucoup. · Tu m'en parles demain ?$p$),
('cd67ae05-3748-57ab-a335-71aa43b8a1c8'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,19,'B2',$p$writing$p$,$p$gramatica$p$,$p$subjonctif_passe$p$,$p$Subjonctif passé: la duda sobre algo ya ocurrido$p$,$p$El subjonctif passé expresa una acción anterior o ya terminada en un contexto que exige subjuntivo (emoción, duda, necesidad). Se forma con el subjonctif présent de avoir o être + el participio pasado: «que j'aie fait», «qu'il soit venu». La elección del auxiliar sigue las mismas reglas que el passé composé, y con être hay concordancia: «qu'elle soit partie», «qu'ils soient arrivés». Se usa cuando la acción del subjuntivo es ANTERIOR a la del verbo principal: «Je suis content que tu sois venu» (viniste antes de que yo esté contento). El error frecuente es usar el subjonctif présent para algo ya pasado: «je doute qu'il soit venu» (pasado), no «qu'il vienne».$p$,$p$Je suis ravi que tu aies réussi. · Bien qu'elle soit partie tôt, elle a raté le train. · Il faut que j'aie fini avant midi.$p$),
('04c71e58-6ad8-5376-9b5b-6014459514d9'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,20,'B2',$p$writing$p$,$p$gramatica$p$,$p$conditionnel_passe_irreel$p$,$p$Lo que habría pasado: el arrepentimiento en francés$p$,$p$Para expresar una hipótesis imposible en el pasado (lo irreal), se usa «si + plus-que-parfait, conditionnel passé»: «Si j'avais su, je serais venu» (si hubiera sabido, habría venido). El conditionnel passé se forma con el conditionnel présent de avoir/être + participio: «j'aurais fait», «il serait parti». Sirve también para el reproche o el arrepentimiento con devoir y pouvoir: «j'aurais dû partir» (debería haber partido), «tu aurais pu me le dire» (podrías habérmelo dicho). El error clásico del hispanohablante es poner el conditionnel en el «si»: NUNCA «si j'aurais su», siempre «si j'avais su». El condicional va solo en la consecuencia.$p$,$p$Si tu m'avais appelé, je serais venu. · J'aurais dû étudier davantage. · Ils auraient pu nous prévenir.$p$),
('89ff861b-a18b-5c38-a902-3572b97aecbc'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,21,'B2',$p$listening$p$,$p$gramatica$p$,$p$discours_indirect_avance$p$,$p$Discurso indirecto avanzado: el futuro se vuelve condicional$p$,$p$En el discurso indirecto en pasado, además del retroceso ya visto, el futur se convierte en conditionnel présent y el futur antérieur en conditionnel passé: «Il a dit : je partirai» → «Il a dit qu'il partirait». Para reportar preguntas sin palabra interrogativa clara, «qu'est-ce qui» se vuelve ce qui (sujeto) y «qu'est-ce que» se vuelve ce que (complemento): «Qu'est-ce que tu veux ?» → «Il a demandé ce que je voulais»; «Qu'est-ce qui se passe ?» → «Il a demandé ce qui se passait». El hispanohablante suele mantener el futuro («il a dit qu'il partira») o traducir «qué» siempre por que, olvidando ce que / ce qui. También hay que ajustar los marcadores de tiempo: demain → le lendemain, hier → la veille.$p$,$p$Elle a annoncé qu'elle déménagerait le lendemain. · Je me demandais ce que tu ferais. · Il a voulu savoir ce qui n'allait pas.$p$),
('254c3721-e0ec-5dd2-bf8d-7a1d060c7279'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,22,'B2',$p$reading$p$,$p$gramatica$p$,$p$participe_present_gerondif$p$,$p$En -ant: participe présent, gérondif y adjetivo verbal$p$,$p$La forma en -ant tiene tres usos que conviene distinguir. El participe présent es invariable y expresa una causa o una acción simultánea: «Ne sachant pas la réponse, il s'est tu». El gérondif es «en + -ant» e indica la manera o el momento de otra acción del MISMO sujeto: «Il chante en travaillant» (canta mientras trabaja). El adjetivo verbal sí concuerda con el nombre y describe una cualidad: «une histoire fascinante», «des enfants charmants». Ojo con la ortografía: el gérondif conserva la raíz verbal (fatiguant, provoquant) mientras que el adjetivo cambia (fatigant, provocant). El error del hispanohablante es usar el gérondif como en español para una acción en curso: no se dice «je suis mangeant», sino «je suis en train de manger».$p$,$p$En arrivant, j'ai vu la lumière allumée. · C'est une journée fatigante (adjetivo). · Se fatiguant vite, il a fait une pause (participe).$p$),
('f340bc52-57b8-527f-a709-e0f8ac28daa9'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,23,'B2',$p$writing$p$,$p$gramatica$p$,$p$connecteurs_b2$p$,$p$Bien que + subjonctif vs alors que + indicatif$p$,$p$En B2 hay que dominar qué conectores rigen subjuntivo y cuáles indicativo. Exigen SUBJONCTIF: bien que y quoique (aunque), à condition que y pourvu que (con tal de que), pour que y afin que (para que), avant que, sans que, jusqu'à ce que. Van con INDICATIF: alors que y tandis que (mientras que, oposición), parce que (porque), puisque (ya que), pendant que (mientras). El error típico es confundir bien que (concesión, subjuntivo: «bien qu'il soit tard») con alors que (contraste, indicativo: «il dort alors qu'il est midi»). Regla práctica: si el conector expresa algo incierto, un objetivo o una condición, casi siempre pide subjonctif; si constata un hecho real, pide indicativo.$p$,$p$Bien qu'il pleuve, nous sortirons. · Je t'aide à condition que tu fasses ta part. · Il travaille alors que ses amis se reposent.$p$),
('36ad82f2-141e-55a1-be20-9486dc47c308'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,24,'B2',$p$reading$p$,$p$gramatica$p$,$p$voix_passive_mise_en_relief$p$,$p$La voz pasiva y el arte de resaltar con c'est... qui$p$,$p$La voz pasiva se forma con être conjugado + participio pasado (que concuerda con el sujeto) + par para el agente: «La lettre a été écrite par Marie». Solo los verbos con complemento directo pueden pasivarse. Para poner de relieve un elemento de la frase, el francés usa dos estructuras muy naturales: «c'est... qui» resalta el sujeto («C'est Marie qui a écrit la lettre») y «c'est... que» resalta otro complemento («C'est cette lettre que j'attendais»). Para destacar toda una idea se usa «ce qui... c'est» / «ce que... c'est»: «Ce que j'aime, c'est le calme». El hispanohablante abusa de la pasiva como en inglés; en francés a menudo es más idiomático usar «on» («on a écrit la lettre») o la mise en relief. Cuidado con la concordancia del participio en la pasiva: «les livres ont été vendus».$p$,$p$Ce roman a été traduit en dix langues. · C'est toi qui as raison. · Ce qui compte, c'est la santé.$p$),
('c05dc8b8-3ec2-5d4d-a5cf-f321fbb05c67'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,13,'B1',$p$writing$p$,$p$gramatica$p$,$p$congiuntivo_presente$p$,$p$Penso che… pide subjuntivo, no indicativo$p$,$p$Tras verbos de opinión, duda o deseo (penso, credo, spero, voglio che, è importante che) el italiano usa el CONGIUNTIVO presente, no el presente normal. El error clásico del hispanohablante es traducir «creo que es» por «credo che è»: en italiano suena mal, va «credo che sia». Ojo también con las tres personas del singular: son idénticas (io/tu/lui sia), así que a veces conviene añadir el pronombre. Verbos clave: essere→sia, avere→abbia, fare→faccia, andare→vada.$p$,$p$Penso che tu abbia ragione · Credo che Marco sia stanco · Spero che faccia bel tempo$p$),
('e5331488-7737-5aef-bf2c-defbbffec9ef'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,14,'B1',$p$writing$p$,$p$gramatica$p$,$p$futuro_condizionale_ipotetico$p$,$p$Se piove, resto: la hipótesis real va en indicativo$p$,$p$El periodo hipotético de tipo I (algo probable) usa indicativo en las dos partes: «se + presente/futuro, presente/futuro». No metas subjuntivo aquí: «se ho tempo, vengo» (no «se abbia tempo»). El condizionale (vorrei, mi piacerebbe, potrei) sirve para pedir con cortesía o expresar deseos, y se forma sobre la raíz del futuro (-erei/-irei). Cuidado: «vorrei» ≠ «voglio»; el primero es amable, el segundo puede sonar brusco.$p$,$p$Se domani piove, resto a casa · Vorrei un caffè, per favore · Mi piacerebbe visitare Roma$p$),
('aa2b5261-309e-5626-bde4-db7f3e4db21c'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,15,'B1',$p$reading$p$,$p$gramatica$p$,$p$pronomi_relativi$p$,$p$che para todo, cui detrás de preposición$p$,$p$«Che» sirve como sujeto y objeto directo y es invariable: «il libro che leggo», «la ragazza che parla». Pero después de una preposición (a, di, con, per, in…) NO se usa «che», sino «cui»: «la persona a cui scrivo», «il motivo per cui vengo». El hispanohablante tiende a decir «la persona che scrivo a», que es incorrecto. «Il quale/la quale» es una alternativa más formal que sí concuerda en género y número.$p$,$p$Il film che ho visto è bello · L'amico di cui ti parlo · La casa in cui vivo$p$),
('e3013220-b68b-5ad5-9e56-9c97493a90a8'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,16,'B1',$p$writing$p$,$p$gramatica$p$,$p$concordanza_participio$p$,$p$È andata, l'ho vista: cuándo concuerda el participio$p$,$p$Con el auxiliar ESSERE el participio concuerda siempre con el sujeto: «Maria è andata», «i ragazzi sono partiti». Con AVERE normalmente queda en -o invariable («ho mangiato la pizza»), PERO si delante hay el pronombre lo/la/li/le, el participio concuerda con ese pronombre: «l'ho vista» (la pizza), «li ho comprati» (i libri). Este último detalle no existe en español y suele olvidarse: no digas «l'ho visto» si te refieres a «la».$p$,$p$Lei è uscita presto · Le chiavi? Le ho perse · Ho visto Anna → L'ho vista$p$),
('40f914f6-e9b0-5b02-b636-4402d2c42255'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,17,'B1',$p$listening$p$,$p$gramatica$p$,$p$discorso_indiretto$p$,$p$Dice che… al pasar del directo al indirecto$p$,$p$Al reportar lo que alguien dice, «dice che» + presente mantiene el tiempo; pero con «ha detto che» (pasado) los tiempos retroceden: presente→imperfetto, futuro→condizionale passato, passato prossimo→trapassato. También cambian las personas y los tiempos/lugares: «io»→«lui/lei», «oggi»→«quel giorno», «qui»→«lì». Error típico: dejar «ha detto che viene» cuando el original era futuro; lo correcto suele ser «ha detto che sarebbe venuto».$p$,$p$«Sono stanco» → Dice che è stanco · «Verrò» → Ha detto che sarebbe venuto · «Vivo qui» → Ha detto che viveva lì$p$),
('95b2adf6-9159-5e61-96d1-d6ce5ab39bb2'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,18,'B1',$p$speaking$p$,$p$gramatica$p$,$p$pronomi_combinati_ci_ne$p$,$p$Glielo, ne, ci: los pronombres que se fusionan$p$,$p$Cuando juntas un pronombre indirecto y uno directo, el indirecto cambia: mi/ti/gli/le + lo/la/li/le → «me lo», «te la», y sobre todo gli/le → «glielo/gliela» (¡una sola palabra, vale para él, ella y usted!). «Ne» sustituye «di + algo» o una cantidad («Quanti ne vuoi? Ne voglio due»). «Ci» sustituye «a/in un lugar o cosa» («Vai a Roma? Sì, ci vado»). El español no tiene «ne/ci», así que hay que entrenarlos aparte.$p$,$p$Glielo dico domani · Vuoi del pane? Sì, ne voglio · Ci penso io$p$),
('0e3ef29a-0ecf-5945-8fc2-e873a4d51691'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,19,'B2',$p$writing$p$,$p$gramatica$p$,$p$congiuntivo_imperfetto_trapassato$p$,$p$Pensavo che fosse: el subjuntivo también tiene pasado$p$,$p$Cuando el verbo principal está en pasado (pensavo, credevo, volevo, era importante che), el subjuntivo que le sigue NO es el presente, sino el congiuntivo imperfetto: «pensavo che fosse tardi», «credevo che avesse ragione». Si el hecho es anterior, se usa el trapassato: «pensavo che avesse già mangiato». El hispanohablante suele decir «pensavo che è» o «pensavo che sia»: ambas son incorrectas. Formas clave: essere→fosse, avere→avesse, fare→facesse.$p$,$p$Pensavo che tu fossi a casa · Credevo che avesse più tempo · Non sapevo che fosse già partito$p$),
('bea64839-7671-57fb-9a07-50c11932a1f0'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,20,'B2',$p$writing$p$,$p$gramatica$p$,$p$periodo_ipotetico_condizionale_passato$p$,$p$Se avessi tempo, verrei: la hipótesis irreal$p$,$p$El periodo hipotético II (irreal en el presente) combina congiuntivo imperfetto + condizionale presente: «se avessi tempo, verrei». El tipo III (irreal en el pasado, algo que ya no pudo ser) usa congiuntivo trapassato + condizionale passato: «se avessi studiato, avrei superato l'esame». Error frecuentísimo del hispanohablante: meter condicional en la parte del «se» («se avrei tempo» ✗). En la subordinada con «se» NUNCA va el condizionale.$p$,$p$Se fossi ricco, viaggerei · Se avessi saputo, te l'avrei detto · Se non avesse piovuto, saremmo usciti$p$),
('4051d5de-73f9-5f47-a83d-1a79c4dc4c75'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,21,'B2',$p$reading$p$,$p$gramatica$p$,$p$forma_passiva$p$,$p$Essere, venire o andare: tres pasivas distintas$p$,$p$La pasiva con «essere» es la neutra: «la lettera è stata scritta». Con «venire» se enfoca la acción/proceso y solo funciona en tiempos simples: «la porta viene chiusa alle otto» (= se cierra). Con «andare» se expresa obligación: «il modulo va compilato» (= debe rellenarse). Además existe el «si passivante»: «si vendono case» (= se venden casas), muy usado. El agente se introduce con «da»: «scritto DA Marco», no «per».$p$,$p$Il libro è stato pubblicato nel 2020 · La cena viene servita alle otto · Le regole vanno rispettate · Qui si parlano tre lingue$p$),
('8bdcde6f-1bc9-5559-9d00-702d719789d7'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,22,'B2',$p$listening$p$,$p$gramatica$p$,$p$discorso_indiretto_avanzato$p$,$p$Concordanza dei tempi: encajar todos los tiempos al reportar$p$,$p$Con un verbo introductor en pasado (disse, aveva detto che…) todo el discurso retrocede de forma sistemática: presente→imperfetto, passato prossimo→trapassato prossimo, futuro→condizionale passato, imperativo→di + infinito o congiuntivo imperfetto. También cambian marcadores: «domani»→«il giorno dopo», «ieri»→«il giorno prima». El error del hispanohablante es no retroceder el futuro: «disse che verrà» debe ser «disse che sarebbe venuto».$p$,$p$«Ho finito» → Disse che aveva finito · «Partirò domani» → Disse che sarebbe partito il giorno dopo · «Aspettami!» → Mi disse di aspettarlo$p$),
('2bffe549-f41c-56fd-8530-d6c4aea0d856'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,23,'B2',$p$writing$p$,$p$gramatica$p$,$p$connettivi_benche_sebbene$p$,$p$Benché con subjuntivo, anche se con indicativo$p$,$p$Los conectores concesivos «benché, sebbene, nonostante, malgrado» exigen SIEMPRE congiuntivo: «benché sia tardi, esco». En cambio «anche se» va con indicativo: «anche se è tardi, esco». Muchos hispanohablantes usan «benché» con indicativo por analogía con «aunque», y suena mal. Otros conectores útiles de B2: «affinché/perché» (finalidad) + congiuntivo, «a meno che» + congiuntivo con non, «purché» (con tal de que) + congiuntivo.$p$,$p$Sebbene piova, usciamo · Anche se piove, usciamo · Te lo spiego affinché tu capisca · Verrò, purché tu mi aspetti$p$),
('291bdb00-3dd4-5701-818f-106854f7c5c5'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,24,'B2',$p$reading$p$,$p$gramatica$p$,$p$nominalizzazione_frasi_scisse$p$,$p$È stato Marco a farlo: cómo poner el foco$p$,$p$La frase scissa (hendida) resalta un elemento con «essere… che/a»: «è Marco che ha telefonato», «è stato Marco A farlo» (con verbo → «a + infinito»). Sirve para enfatizar quién, qué o cuándo, como el «fue X quien…» español. La nominalizzazione convierte un verbo en sustantivo con «il + infinito»: «il fumare fa male», «con l'andare del tempo». Es un registro más culto, típico del italiano escrito y formal de nivel B2.$p$,$p$È stato Marco a rompere il vaso · È qui che ci siamo conosciuti · Il leggere aiuta la mente · Con il passare degli anni$p$),
('8e0631c7-bba4-54aa-9c05-fbd8479d1219'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,13,'B1',$p$writing$p$,$p$gramatica$p$,$p$konjunktiv_2$p$,$p$El Konjunktiv II: pedir con cortesía y soñar despierto$p$,$p$El Konjunktiv II es el modo de lo hipotético y lo cortés. Para casi todos los verbos usas «würde» + infinitivo al final: «Ich würde gern kommen». Pero los verbos más frecuentes tienen forma propia que suena más natural: «haben»→hätte, «sein»→wäre, «können»→könnte, «werden»→würde. Ojo hispanohablante: no traduzcas el condicional español con futuro; «me gustaría» no es «ich werde», sino «ich würde gern» o «ich hätte gern». Y recuerda que en «würde …» el infinitivo va SIEMPRE al final.$p$,$p$Ich hätte gern einen Kaffee. · Könnten Sie mir bitte helfen? · Ich würde gern nach Berlin reisen.$p$),
('a90f4018-fed4-552b-bd4e-ea0b5237469a'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,14,'B1',$p$writing$p$,$p$gramatica$p$,$p$nebensaetze_konnektoren$p$,$p$Frases subordinadas: el verbo se va al final$p$,$p$Con conjunciones como «weil» (porque), «dass» (que) u «obwohl» (aunque) empieza una subordinada, y ahí el verbo conjugado salta al FINAL: «Ich bleibe zu Hause, weil ich krank bin». Este es el error nº 1 del hispanohablante: decir «weil ich bin krank» copiando el orden español. Distinto son los adverbios «deshalb» (por eso) y «trotzdem» (a pesar de eso): NO mandan el verbo al final, sino que ocupan la posición 1 y el verbo va en 2ª: «Ich bin krank, deshalb bleibe ich zu Hause».$p$,$p$Ich lerne Deutsch, weil ich in Wien arbeite. · Er kommt nicht, obwohl er Zeit hat. · Es regnet, deshalb nehme ich den Bus.$p$),
('433c045c-827c-5942-a803-2a7f81b29d76'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,15,'B1',$p$reading$p$,$p$gramatica$p$,$p$relativsaetze$p$,$p$Relativos der/die/das: concuerdan en género, mandan el verbo al final$p$,$p$El pronombre relativo (der/die/das/den/dem…) toma el GÉNERO del sustantivo al que se refiere, pero su CASO depende de la función dentro de la subordinada. «Der Mann, der dort steht» (sujeto→der) frente a «Der Mann, den ich kenne» (objeto directo→den) o «Der Mann, dem ich helfe» (dativo→dem). Como toda subordinada, el verbo va al final. Truco: casi siempre coinciden con el artículo definido, salvo el dativo plural «denen» y los genitivos «dessen/deren». No lo traduzcas todo por «que»: el alemán distingue el caso.$p$,$p$Das Buch, das ich lese, ist spannend. · Die Frau, die dort wohnt, ist Ärztin. · Der Freund, dem ich vertraue, hilft mir.$p$),
('bf588112-227b-598f-8d85-a9c82145fcd0'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,16,'B1',$p$reading$p$,$p$gramatica$p$,$p$passiv$p$,$p$La voz pasiva: werden + participio (¡no sein!)$p$,$p$La pasiva de proceso se forma con «werden» conjugado + el participio II al final: «Das Haus wird gebaut» (la casa se construye/es construida). En pasado usas «wurde»: «Das Haus wurde 1990 gebaut». Cuidado: el hispanohablante tiende a usar «sein» («ist gebaut») porque se parece a «ser/estar», pero eso es el resultado, no la acción. Quien hace la acción (el agente) se introduce con «von»: «Der Brief wird von Anna geschrieben». Muchas veces el agente ni se menciona, que es justo la gracia de la pasiva.$p$,$p$Hier wird ein Krankenhaus gebaut. · Der Kuchen wurde gestern gebacken. · Die E-Mail wird von der Chefin geschrieben.$p$),
('fec9b9e8-173a-5563-aba0-ea14f6375d31'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,17,'B1',$p$writing$p$,$p$error_comun$p$,$p$verben_praeposition_genitiv$p$,$p$Verbos con preposición fija y el genitivo «des»$p$,$p$Muchos verbos alemanes exigen una preposición concreta que NO se traduce literal del español: «warten auf» (esperar A), «denken an» (pensar EN), «Angst haben vor» (tener miedo DE). Hay que aprenderlos como bloque, con su caso: «Ich warte auf den Bus» (auf + acusativo). Además, el genitivo marca posesión y termina en «-s» en masculino/neutro: «das Auto des Mannes», «der Titel des Buches». Error típico: usar «von» para todo («das Auto von dem Mann»); es válido al hablar, pero el genitivo es lo culto y lo que se espera por escrito.$p$,$p$Ich warte auf meinen Bruder. · Sie hat Angst vor der Prüfung. · Das ist das Ende des Films.$p$),
('483adacc-0ff2-5682-b503-041651c7a8c5'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,18,'B1',$p$writing$p$,$p$gramatica$p$,$p$konjunktiv_2_vergangenheit$p$,$p$Konjunktiv II del pasado: lo que habría pasado$p$,$p$Para hablar de hipótesis IRREALES en el pasado («habría venido», «lo habría sabido») usas «hätte» o «wäre» + participio II al final: «Ich hätte dir geholfen» (te habría ayudado), «Wir wären früher gekommen» (habríamos venido antes). Eliges «wäre» con los mismos verbos que forman el Perfekt con «sein» (movimiento/cambio: kommen, gehen, sein, bleiben), y «hätte» con el resto. Muy usado con «wenn»: «Wenn ich Zeit gehabt hätte, wäre ich gekommen». Ojo: el participio y el auxiliar cierran la frase, nunca al principio.$p$,$p$Ich hätte das nicht gesagt. · Wenn es nicht geregnet hätte, wären wir spazieren gegangen. · Sie wäre gern länger geblieben.$p$),
('79b84465-560a-5d1d-a7ce-8f01fae0ef90'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,19,'B2',$p$reading$p$,$p$gramatica$p$,$p$konjunktiv_1$p$,$p$Konjunktiv I: el estilo indirecto del periodista$p$,$p$El Konjunktiv I marca el estilo indirecto formal: repites lo que otro dijo sin comprometerte con su verdad. Se forma sobre la raíz del infinitivo + terminaciones propias: «haben»→er habe, «sein»→er sei, «werden»→er werde, «können»→er könne. Lo verás sobre todo en prensa y textos formales: «Der Minister sagte, er habe keine Zeit». En el habla cotidiana muchos usan el indicativo o el Konjunktiv II, pero para B2 debes RECONOCERLO al leer. Si la forma del Konjunktiv I coincide con el indicativo, se recurre al Konjunktiv II para dejar claro que es cita.$p$,$p$Sie sagt, sie sei müde. · Er behauptet, er habe nichts gewusst. · Die Zeitung schreibt, die Preise würden steigen.$p$),
('4a26c41e-d2bd-5dc4-952c-db653c29cd29'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,20,'B2',$p$writing$p$,$p$gramatica$p$,$p$passiv_erweitert$p$,$p$Pasiva avanzada: con modales, de estado y «sich lassen»$p$,$p$En B2 la pasiva se combina con verbos modales: el modal se conjuga y «werden» va en infinitivo al final: «Das muss heute gemacht werden» (esto debe hacerse hoy). Distingue la pasiva de PROCESO (werden + participio: «Die Tür wird geöffnet») de la pasiva de ESTADO o Zustandspassiv (sein + participio: «Die Tür ist geöffnet» = ya está abierta, resultado). Y una joya elegante: «sich lassen» + infinitivo sustituye a «kann … werden»: «Das Problem lässt sich lösen» = «Das Problem kann gelöst werden». Suena mucho más natural y culto.$p$,$p$Der Bericht muss bis morgen geschrieben werden. · Das Fenster ist schon geschlossen. · Der Fehler lässt sich leicht beheben.$p$),
('3520685d-535e-564d-9d1e-aa6bfcdbcb6b'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,21,'B2',$p$reading$p$,$p$gramatica$p$,$p$partizip_als_adjektiv$p$,$p$El participio como adjetivo: das reparierte Auto$p$,$p$Los participios pueden ponerse DELANTE del sustantivo como un adjetivo, y entonces se declinan igual que cualquier adjetivo. El participio II expresa algo ya hecho, con sentido pasivo: «das reparierte Auto» (el coche reparado), «die geschriebene E-Mail». El participio I (infinitivo + -d) expresa algo en curso, activo: «das lachende Kind» (el niño que ríe), «die steigenden Preise». Error del hispanohablante: olvidar la terminación de declinación según género/caso/artículo («ein repariertes Auto», neutro con «ein»→ -es). Esta construcción condensa una relativa entera en una sola palabra: muy típica del alemán escrito.$p$,$p$das frisch gestrichene Zimmer · ein weinendes Baby · die eben angekommenen Gäste$p$),
('e39b125f-30c6-52d9-b50d-6cdc63c4b498'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,22,'B2',$p$writing$p$,$p$gramatica$p$,$p$konnektoren_b2$p$,$p$Conectores dobles: je…desto, sowohl…als auch, weder…noch$p$,$p$Los conectores correlativos dan riqueza a tu escritura. «Je + comparativo …, desto + comparativo …»: cuanto más…, más…, y ¡ojo al orden! tras «je» el verbo va al final, tras «desto» va en 2ª posición: «Je mehr ich lerne, desto besser verstehe ich». «Sowohl … als auch» = tanto… como; «weder … noch» = ni… ni (fíjate: «noch» ya es negativo, no añadas «nicht»); «nicht nur … sondern auch» = no solo… sino también. Estos pares elevan el nivel de inmediato y evitan las frases cortas y sueltas.$p$,$p$Je älter man wird, desto ruhiger wird man. · Sie spricht sowohl Deutsch als auch Spanisch. · Er ist nicht nur klug, sondern auch fleißig.$p$),
('741a6d50-9f8f-5c4c-a09a-f13f36cbb9eb'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,23,'B2',$p$writing$p$,$p$gramatica$p$,$p$nominalisierung_funktionsverben$p$,$p$Nominalización y verbos funcionales: el registro culto$p$,$p$El alemán formal prefiere los sustantivos a los verbos. Cualquier infinitivo se convierte en sustantivo NEUTRO con mayúscula: «lesen»→das Lesen, «rauchen»→das Rauchen («Das Lesen entspannt mich»). Junto a esto están las Funktionsverbgefüge: pares fijos nombre+verbo donde el verbo casi pierde significado propio: «eine Entscheidung treffen» (tomar una decisión), «in Frage stellen» (poner en duda), «zur Verfügung stehen» (estar a disposición). No los traduzcas literal: no es «eine Entscheidung machen». Aprende cada combinación como una unidad; son el sello del lenguaje profesional y académico.$p$,$p$Das Rauchen ist hier verboten. · Wir müssen eine Entscheidung treffen. · Diese Aussage stelle ich in Frage.$p$),
('79610ea9-6db7-5522-bcce-6243704635c6'::uuid,'20000000-0000-0000-0000-000000000005'::uuid,24,'B2',$p$writing$p$,$p$gramatica$p$,$p$genitiv_praepositionen_da_wo$p$,$p$Preposiciones de genitivo y las partículas da(r)-/wo(r)-$p$,$p$Preposiciones como «wegen» (a causa de), «trotz» (a pesar de), «während» (durante) y «aufgrund» rigen GENITIVO: «wegen des Wetters», «trotz des Regens», «während der Woche». Marcan un registro cuidado. Por otro lado, para no repetir «cosas» tras una preposición, el alemán usa las partículas «da(r)-» y «wo(r)-»: en vez de «über das» dices «darüber» (sobre eso), «damit» (con eso), «dafür» (para eso); y para preguntar, «worüber?» (¿sobre qué?), «womit?» (¿con qué?). La «-r-» aparece solo si la preposición empieza por vocal (da+auf→darauf). Estas partículas evitan repetir el objeto y suenan totalmente nativas.$p$,$p$Wegen des schlechten Wetters bleiben wir zu Hause. · Trotz der Kälte gehen wir spazieren. · Worüber sprecht ihr? – Wir sprechen darüber.$p$),
('40bfbbc1-207b-5f04-8fcf-acaf646ae2a4'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,13,'B1',$p$writing$p$,$p$gramatica$p$,$p$conditionalis$p$,$p$«Zou» + infinitivo: pedir, desear, imaginar$p$,$p$Para expresar cortesía, deseos o hipótesis, el neerlandés usa «zou/zouden» + infinitivo al FINAL. «Zou» es la forma condicional de «zullen». Ojo: el infinitivo se va al final de la frase, no pegado a «zou» como en español («yo compraría» → «ik zou … kopen», con lo demás en medio). Para pedir algo con educación, «zou je … willen/kunnen» suena mucho más amable que el imperativo directo.$p$,$p$Ik zou graag een koffie willen. · Zou je het raam kunnen openen? · Als ik rijk was, zou ik een huis kopen.$p$),
('43cf1232-6e6e-58a6-8835-933819f13321'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,14,'B1',$p$writing$p$,$p$gramatica$p$,$p$bijzinnen_voegwoorden$p$,$p$Subordinadas: el verbo se va al FINAL$p$,$p$Tras un voegwoord subordinante (omdat, dat, hoewel, als, terwijl…) el verbo conjugado salta al FINAL de la bijzin. Este es EL error clásico del hispanohablante: mantiene el orden V2 («omdat ik ben moe») cuando debe decir «omdat ik moe ben». Distinto son «daarom» y «dus» (adverbio/coordinante): NO mandan el verbo al final y «daarom» provoca inversión (verbo antes del sujeto).$p$,$p$Ik blijf thuis omdat ik ziek ben. · Hoewel het regent, gaan we wandelen. · Ik ben moe, daarom ga ik slapen.$p$),
('217c7ddc-3009-5320-ad34-b666bf70c334'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,15,'B1',$p$writing$p$,$p$gramatica$p$,$p$relatieve_bijzinnen$p$,$p$«die» o «dat»: el relativo según de/het$p$,$p$El pronombre relativo depende del género de la palabra a la que se refiere: «die» para de-woorden (y todos los plurales), «dat» para het-woorden. Para personas también «wie» tras preposición (de man met wie…) y «waar» para lugares o combinado con preposición (waarop, waarin). Recuerda: la relativa es una bijzin, así que el verbo va al FINAL.$p$,$p$De vrouw die daar woont, is arts. · Het boek dat ik lees, is spannend. · Het dorp waar ik ben geboren, is klein.$p$),
('204ca68e-ecb8-58ab-ae5b-d076cf1b3c98'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,16,'B1',$p$reading$p$,$p$gramatica$p$,$p$lijdende_vorm$p$,$p$La voz pasiva: «worden» + participio$p$,$p$La pasiva presente/pasado se forma con «worden/werd» + voltooid deelwoord al final; el agente se introduce con «door». Cuidado: el neerlandés usa «worden», NO «zijn», para la acción («el pan se hace» = het brood wordt gebakken). «Zijn» + participio expresa el RESULTADO/estado, no la acción. El deelwoord siempre cierra la frase.$p$,$p$De brief wordt door Jan geschreven. · Het huis werd in 1900 gebouwd. · De ramen worden elke week schoongemaakt.$p$),
('5f9f17d4-cb71-584b-84d8-8c610c59f079'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,17,'B1',$p$writing$p$,$p$error_comun$p$,$p$vaste_voorzetsels_om_te$p$,$p$Preposiciones fijas y «om … te»$p$,$p$Muchos verbos neerlandeses exigen una preposición fija que NO coincide con el español: wachten OP (esperar), denken AAN (pensar en), houden VAN (querer/gustar), zoeken NAAR. Hay que memorizarlas como bloque. Para expresar finalidad («para hacer algo») se usa «om … te» + infinitivo al final: «om te leren». Error típico: calcar «esperar a alguien» como «wachten voor».$p$,$p$Ik wacht op de bus. · Zij houdt van muziek. · Ik ga naar de winkel om brood te kopen.$p$),
('81a4cbad-1477-5dfe-bdce-25d10bb8b155'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,18,'B1',$p$writing$p$,$p$gramatica$p$,$p$voltooid_verleden_conditionalis_verleden$p$,$p$Pluscuamperfecto y condicional pasado$p$,$p$El voltooid verleden tijd («había hecho») usa «had/was» + voltooid deelwoord: elige «had» o «was» según el verbo lleve hebben o zijn en el perfecto. El condicional pasado («habría hecho») es «zou hebben/zijn» + deelwoord. Se combinan en frases hipotéticas: «als ik het had geweten, zou ik zijn gekomen». El participio cierra cada oración.$p$,$p$Ik had het al gedaan. · Zij was al vertrokken. · Als ik tijd had gehad, zou ik je hebben geholpen.$p$),
('ecfad17e-b980-5096-b5ea-9c7a23876f23'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,19,'B2',$p$writing$p$,$p$gramatica$p$,$p$indirecte_rede$p$,$p$Estilo indirecto: el desplazamiento temporal$p$,$p$Al pasar del estilo directo al indirecto, los tiempos «retroceden»: tegenwoordige tijd → verleden tijd, perfectum → voltooid verleden (had), y «zal» → «zou». Se introduce con «dat» para afirmaciones y «of» para preguntas de sí/no. Recuerda que tras «dat/of» el verbo va al FINAL. Error típico del hispanohablante: usar «als» donde toca «of» en la interrogativa indirecta.$p$,$p$Hij zei dat hij moe was. · Ze vroeg of ik kwam. · Hij zei dat hij het al had gedaan.$p$),
('4055c201-ce63-5b9b-8029-e9a5c195d745'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,20,'B2',$p$reading$p$,$p$gramatica$p$,$p$lijdende_vorm_gevorderd$p$,$p$Pasiva avanzada: modales, «er wordt» e «is + deelwoord»$p$,$p$La pasiva con modales pone el modal en V2 y «worden» + deelwoord al final: «het moet gedaan worden». La pasiva impersonal «er wordt…» sirve cuando no hay sujeto concreto (er wordt gedanst = se baila). Clave B2: en el PERFECTO de la pasiva se dice «is/zijn + deelwoord» SIN «geworden» (de brief is geschreven), aunque «worden» normalmente lleve «geworden» en su perfecto de cambio de estado.$p$,$p$Het werk moet vandaag gedaan worden. · Er wordt hier veel gewerkt. · De brief is al verstuurd.$p$),
('a3b832f8-6f61-5f43-aaeb-f47be6a9690f'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,21,'B2',$p$writing$p$,$p$gramatica$p$,$p$deelwoord_als_bijvoeglijk$p$,$p$El participio como adjetivo: -end vs voltooid$p$,$p$Los participios pueden funcionar como adjetivo delante del sustantivo. El tegenwoordig deelwoord (-end, acción en curso, «que…-a») y el voltooid deelwoord (resultado, «-ado») se DECLINAN como adjetivos: reciben «-e» salvo ante het-woord indefinido, donde van sin terminación. Error típico: olvidar la «-e» de concordancia. «lachend kind» → «het lachende kind».$p$,$p$de lachende kinderen · een gesloten deur · het gebroken glas · de spelende hond$p$),
('31450efd-ebd5-5ded-b586-e426ec2fe6e7'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,22,'B2',$p$writing$p$,$p$gramatica$p$,$p$complexe_voegwoorden$p$,$p$Conectores complejos e inversión$p$,$p$Los adverbios conectores «niettemin, desondanks, daarentegen, toch» arrancan la frase y FUERZAN inversión (verbo antes del sujeto): «Desondanks kwam hij». Los pares correlativos «zowel … als» (tanto…como) y «noch … noch» (ni…ni) unen elementos. «Hoewel» sigue siendo subordinante: manda el verbo al final. No confundas la inversión de los adverbios con el verbo-final de «hoewel».$p$,$p$Het regende; niettemin gingen we naar buiten. · Zowel Jan als Piet komt. · Hoewel hij ziek was, werkte hij door.$p$),
('1ce3dc07-ebed-5833-b298-8a571419f331'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,23,'B2',$p$writing$p$,$p$gramatica$p$,$p$nominalisatie$p$,$p$Nominalización: «het» + infinitivo$p$,$p$El infinitivo neerlandés se sustantiva anteponiéndole «het», y pasa a ser un het-woord: «het lezen» (la lectura/el leer), «het roken is verboden». Es muy frecuente en registro formal y equivale al infinitivo/gerundio sustantivado español. Puede llevar complementos: «het leren van talen». Error típico: usar el infinitivo suelto sin «het» como sujeto.$p$,$p$Het roken is hier verboden. · Het leren van talen kost tijd. · Zwemmen is gezond, maar het zwemmen in de zee is koud.$p$),
('efd08148-070f-5972-a11a-9812266d6dfd'::uuid,'20000000-0000-0000-0000-000000000006'::uuid,24,'B2',$p$writing$p$,$p$gramatica$p$,$p$zou_hebben_zijn_deelwoord$p$,$p$Irrealis del pasado: «zou hebben/zijn» + participio$p$,$p$Para lo que «habría pasado» pero no pasó (irrealis), se usa «zou hebben» o «zou zijn» + voltooid deelwoord, eligiendo hebben/zijn como en el perfecto normal del verbo. Suele acompañar a una condicional con voltooid verleden («als … had/was»). En la principal, «zou» va en V2 y el infinitivo hebben/zijn + el participio cierran la frase. Error típico: colocar mal el orden de los dos verbos finales.$p$,$p$Ik zou het gedaan hebben. · Zij zou eerder zijn gekomen. · Als je had gebeld, zou ik je hebben geholpen.$p$),
('33ecdb02-f685-5fc5-a959-2215f5bc05bd'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,19,'B2',$p$writing$p$,$p$gramatica$p$,$p$presente_subjuntivo_avancado$p$,$p$Subjuntivo tras «embora, caso, a menos que»$p$,$p$En B2 el presente do subjuntivo se dispara con conectores que expresan concesión, condición o finalidad: embora (aunque), para que / a fim de que (para que), caso (en caso de que), a menos que / a não ser que (a menos que), sem que (sin que), antes que (antes de que). El verbo «invierte» la vocal temática: -ar → «que fale», -er → «que coma», -ir → «que parta», y los irregulares clave son ser → «seja», ter → «tenha», fazer → «faça», ir → «vá», estar → «esteja», haver → «haja». El hispanohablante suele acertar el subjuntivo, pero olvida que en portugués «embora» rige subjuntivo SIEMPRE (no «embora está», sino «embora esteja») y confunde «caso» con «se»: tras «caso» va subjuntivo directo, sin «que» («caso precise», no «caso que precisa»).$p$,$p$Embora seja tarde, vou terminar o relatório. · Levo o guarda-chuva caso chova. · Explico de novo para que você entenda. · Não saio a menos que você venha comigo.$p$),
('75330559-e7be-506f-9c1e-7ee78b762a7f'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,20,'B2',$p$writing$p$,$p$error_comun$p$,$p$futuro_do_subjuntivo$p$,$p$«Quando eu tiver»: el futuro do subjuntivo (¡no presente!)$p$,$p$Este es EL rasgo que delata al hispanohablante. Para una condición futura tras quando, se, enquanto, assim que, sempre que o depois que, el portugués usa el futuro do subjuntivo, un tiempo que el español no tiene. Se forma quitando el -ram de la 3ª persona del pretérito perfeito: falaram → «quando eu falar», comeram → «comer», partiram → «partir». Los irregulares nacen del mismo pretérito: ter → «tiver», ser/ir → «for», fazer → «fizer», estar → «estiver», poder → «puder», querer → «quiser», vir → «vier», pôr → «puser». El error clásico es calcar el español y usar el presente: NO «quando eu tenho tempo», sino «quando eu TIVER tempo»; NO «se você quer», sino «se você QUISER». Regla práctica: si la acción del «quando/se» aún no ha ocurrido y mira al futuro, va futuro do subjuntivo.$p$,$p$Quando eu tiver tempo, te ligo. · Se você quiser, a gente marca amanhã. · Assim que ele chegar, começamos. · Enquanto você não estiver pronto, eu espero.$p$),
('36a4cbe9-a122-50b8-a99a-152cedad704f'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,21,'B2',$p$writing$p$,$p$gramatica$p$,$p$periodo_hipotetico$p$,$p$«Se eu tivesse tempo, viajaria»: el condicional irreal$p$,$p$Para la hipótesis irreal en el presente se usa «se + imperfeito do subjuntivo, futuro do pretérito (condicional)»: «Se eu tivesse tempo, viajaria». El imperfeito do subjuntivo se forma quitando el -ram del pretérito y añadiendo -sse: falaram → «falasse», tiveram → «tivesse», fossem → «fosse», fizeram → «fizesse». El futuro do pretérito (condicional) se hace con -ia: falar → «falaria», fazer → «faria», ser → «seria». Para la hipótesis irreal en el pasado (lo que no llegó a pasar) se encadenan los tiempos compuestos: «Se tivesse estudado, teria passado» (si hubiera estudiado, habría aprobado), con ter en imperfeito do subjuntivo + particípio en la condición, y ter en futuro do pretérito + particípio en la consecuencia. El error típico es meter el condicional en el «se»: NUNCA «se eu teria tempo», siempre «se eu tivesse tempo»; el condicional va solo en la consecuencia.$p$,$p$Se eu tivesse dinheiro, compraria a casa. · Se você estudasse mais, tiraria notas melhores. · Se eu tivesse sabido, teria avisado você. · No seu lugar, eu não faria isso.$p$),
('a76fcb12-d962-5e46-97d5-0e2ae6db2035'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,22,'B2',$p$reading$p$,$p$gramatica$p$,$p$voz_passiva$p$,$p$«Foi construído / Vendem-se casas»: las dos pasivas$p$,$p$El portugués tiene dos voces pasivas. La analítica se forma con ser + particípio, que CONCUERDA con el sujeto, y el agente va con por: «A ponte foi construída pelos romanos», «As casas foram vendidas». La pasiva sintética (o pronominal) usa se con verbo en 3ª persona y concuerda con el sujeto: «Vende-se casa» (singular) pero «Vendem-se casas» (plural) — este acuerdo es el error frecuente: no «vende-se casas», sino «vendem-se casas». Ojo también con los particípios duplos: algunos verbos tienen forma regular con ter/haver y una forma corta e irregular con ser/estar. Con la pasiva (ser/estar) se usa la corta: aceitar → «foi aceito» (no «aceitado»), pagar → «a conta foi paga» (no «pagada»), entregar → «foi entregue», ganhar → «foi ganho», gastar → «foi gasto». El hispanohablante también abusa de la pasiva por calco del inglés; en portugués muchas veces es más natural la sintética con se.$p$,$p$O prédio foi construído em 1920. · Alugam-se salas comerciais. · O pacote já foi entregue ontem. · O projeto foi aceito pela diretoria.$p$),
('cba6b4db-bf79-50fa-b128-6ddebfffb76f'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,23,'B2',$p$listening$p$,$p$gramatica$p$,$p$discurso_indireto_colocacao$p$,$p$«Ele disse que…»: reportar y colocar el pronombre$p$,$p$Al pasar al discurso indirecto en pasado, los tiempos retroceden: presente → imperfeito («eu trabalho» → «disse que trabalhava»), pretérito perfeito → mais-que-perfeito («eu fiz» → «disse que tinha feito»), futuro → futuro do pretérito («eu irei» → «disse que iria»). El «que» es obligatorio (no se omite como a veces en inglés). Aquí aparece además la colocação pronominal, muy marcada en portugués: por defecto va la ênclise (pronombre después, con guion): «Disse-me a verdade». Pero ciertas palabras «atraen» el pronombre y fuerzan la próclise (pronombre antes): negaciones (não me disse), palabras interrogativas y relativas (quem me disse, que se passou), adverbios (já me falou, sempre me ajuda) y conjunciones subordinantes (porque me pediu, quando se levantou). El hispanohablante tiende a poner siempre el pronombre antes por calco; en el registro cuidado del pt-BR conviene reconocer cuándo la ênclise es la forma esperada y cuándo un «não», «que» o «já» exige la próclise.$p$,$p$Ela disse que estava cansada e que ligaria depois. · Não me contaram o que tinha acontecido. · Ele perguntou-me se eu viria. · Já te avisei que a reunião foi adiada.$p$),
('d5b3da0c-d76f-57e6-84e4-da743e5f4c00'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,24,'B2',$p$writing$p$,$p$gramatica$p$,$p$conectores_regencia$p$,$p$Conectores B2 + la preposición que exige el verbo$p$,$p$Cierra el B2 dominando qué conector pide subjuntivo y qué verbo pide preposición. Rigen SUBJUNTIVO los que expresan concesión, condición o finalidad: embora, caso, a menos que, para que, nem que. Van con INDICATIVO los que constatan un hecho: à medida que y à proporção que (a medida que), porque, já que / uma vez que (ya que), assim que (una vez cumplido), enquanto (mientras, hecho). El contraste clave es «embora chova» (subjuntivo, concesión) frente a «porque chove» (indicativo, causa real). En cuanto a la regência verbal, muchos verbos rigen una preposición distinta del español: assistir A um filme (ver una película; sin «a» significa «ayudar/atender»), obedecer A / desobedecer A alguém, gostar DE algo, precisar DE algo, depender DE, concordar COM, casar-se COM, chegar A / ir A um lugar (no «chegar em» en la norma culta), esquecer-se DE. El error típico es calcar la preposición española («assistir o filme», «gostar algo», «obedecer alguém») u omitirla.$p$,$p$Embora custe caro, vale a pena. · À medida que envelhecemos, mudamos de ideia. · Ontem assisti a um documentário sobre o Brasil. · Você precisa de ajuda? Não gosto de sair no calor.$p$)
